- **Recommendation**: Use `express.json()` with size limits

Here's an improved version with security best practices implemented:

```javascript
// Secure application with error handling and input validation
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');

const app = express();

// Security: Add security headers
app.use(helmet());

// Security: Configure CORS (adjust as needed for your domain)
app.use((req, res, next) => {
  res.header('Access-Control-Allow-Origin', process.env.ALLOWED_ORIGIN || 'http://localhost:3000');
  res.header('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.header('Access-Control-Allow-Headers', 'Content-Type');
  next();
});

// Logging: Structured logging
app.use(morgan('combined'));

// Input validation: Limit request body size
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ limit: '10mb', extended: true }));

// Security: Rate limiting to prevent DoS
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Health check endpoint (less restrictive)
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Secure users endpoint with validation
app.get('/users', (req, res) => {
  try {
    // Input validation: Validate query parameters
    const limit = parseInt(req.query.limit, 10);
    const skip = parseInt(req.query.skip, 10);

    // Security: Validate parsed values
    if (isNaN(limit) || limit < 0 || limit > 100) {
      return res.status(400).json({ error: 'Invalid limit parameter' });
    }
    if (isNaN(skip) || skip < 0) {
      return res.status(400).json({ error: 'Invalid skip parameter' });
    }

    // Mock data (in production, fetch from secure database)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination
    const paginatedUsers = users.slice(skip, skip + (limit || 10));

    res.json({
      data: paginatedUsers,
      total: users.length,
      limit: limit || 10,
      skip: skip || 0
    });
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't expose internal error details to client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' 
      ? 'Internal server error' 
      : err.message
  });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// Server startup with error handling
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, (error) => {
  if (error) {
    console.error('Failed to start server:', error);
    process.exit(1);
  }
  console.log(`Server running on port ${PORT}`);
});

// Handle uncaught exceptions
process.on('uncaughtException', (error) => {
  console.error('Uncaught exception:', error);
  process.exit(1);
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled rejection at:', promise, 'reason:', reason);
  process.exit(1);
});

module.exports = app;
```

